={{ JSON.stringify({
  chat_id: $env.TELEGRAM_TRADING_CHAT_ID,
  text: '🚨 Workflow error\n\nWorkflow: ' + ($json.workflow ? $json.workflow.name : 'unknown') +
        '\nExecution: ' + ($json.execution ? $json.execution.id : 'unknown') +
        '\nMode: ' + ($json.execution ? $json.execution.mode : 'unknown') +
        '\nNode: ' + ($json.execution && $json.execution.error ? ($json.execution.error.node ? $json.execution.error.node.name : 'n/a') : 'n/a') +
        '\nMessage: ' + ($json.execution && $json.execution.error ? ($json.execution.error.message || 'no message') : 'no error obj') +
        '\nLast node: ' + ($json.execution ? ($json.execution.lastNodeExecuted || 'n/a') : 'n/a')
}) }}

